     7|use Illuminate\Bus\Queueable;
     8|use App\Helpers\PasscodeFileHelper;
     9|use App\Helpers\EncryptedFileHelper;
    10|use App\Exceptions\PasscodeException;
    11|use Illuminate\Queue\SerializesModels;
    12|use Illuminate\Support\Facades\Storage;
    13|use Illuminate\Queue\InteractsWithQueue;
    14|use Illuminate\Contracts\Queue\ShouldQueue;
    15|use Illuminate\Foundation\Bus\Dispatchable;
    16|
    17|class EncryptImage implements ShouldQueue
    18|{
    19|    use Dispatchable, InteractsWithQueue, Queueable, SerializesModels;
    20|
    21|    protected $imageId;
    22|
    23|    /**
    24|     * Create a new job instance.
    25|     */
    26|    public function __construct($imageId)
    27|    {
    28|        $this->imageId = $imageId;
    29|
    30|        $this->onQueue('encryption');
    31|    }
    32|
    33|    /**
    34|     * Execute the job.
    35|     */
    36|    public function handle(): void
    37|    {
    38|        $image = Image::withTrashed()->where('id', $this->imageId)->firstOrFail();
    39|
    40|        if ($image->original_encrypted_at != null) {
    41|            return;
    42|        }
    43|
    44|        try {
    45|            $passcode = (new PasscodeFileHelper)();
    46|        } catch (PasscodeException $th) {
    47|            $this->release(60);
    48|            return;
    49|        }
    50|
    51|        $content = Storage::disk('backblaze')->get($image->path);
    52|
    53|        $encrypted = EncryptedFileHelper::encrypt($content, $passcode);
    54|
    55|        $imageUuid = Str::before($image->name, '.');
    56|
    57|        if ($image->profile_id) {
    58|            $path = "encrypted/images/{$image->profile_id}/{$imageUuid}.enc";
    59|
    60|            Storage::disk('backblaze')->put($path, $encrypted);
    61|        } else {
    62|            $path = "encrypted/bulkUploads/{$imageUuid}.enc";
    63|
    64|            Storage::disk('backblaze')->put($path, $encrypted);
    65|        }
    66|
    67|        if (!Storage::disk('backblaze')->exists($path)) {
    68|            $this->release(1);
    69|            return;
    70|        }
    71|
    72|        $image->original_encrypted_at = now();
    73|        $image->save();
    74|
    75|        sodium_memzero($content);
    76|        sodium_memzero($encrypted);
    77|        sodium_memzero($passcode);
    78|    }
