     9|class PasscodeFileHelper
    10|{
    11|    function __invoke()
    12|    {
    13|        if (Storage::disk('local')->exists('files/passcode.json') === false) {
    14|            throw new PasscodeException('Passcode not set');
    15|        }
    16|
    17|        $encryptedJson = Storage::disk('local')->get('files/passcode.json');
    18|
    19|        $content = $this->decrypt($encryptedJson);
    20|
