     3|namespace App\Helpers;
     4|
     5|class EncryptionHelper
     6|{
     7|    private const NONCE_LENGTH = SODIUM_CRYPTO_SECRETBOX_NONCEBYTES;
     8|    private const KEY_LENGTH = SODIUM_CRYPTO_SECRETBOX_KEYBYTES;
     9|
    10|    /**
    11|     * Krypterer tekst med en forhåndsgenerert 256-bit nøkkel.
    12|     *
    13|     * @param string $plaintext Teksten som skal krypteres
    14|     * @param string $key Base64-kodet 256-bit nøkkel fra nøkkelfil
    15|     * @return string Base64-kodet kryptert streng: nonce + ciphertext
    16|     */
    17|    public static function encrypt(string $plaintext, string $key): string
    18|    {
    19|        $binaryKey = base64_decode($key, true);
    20|
    21|        if ($binaryKey === false || strlen($binaryKey) !== self::KEY_LENGTH) {
    22|            throw new \InvalidArgumentException("Ugyldig nøkkel.");
    23|        }
    24|
    25|        $nonce = random_bytes(self::NONCE_LENGTH);
    26|        $cipher = sodium_crypto_secretbox($plaintext, $nonce, $binaryKey);
    27|
    28|        sodium_memzero($binaryKey);
    29|        sodium_memzero($plaintext);
    30|
    31|        return base64_encode($nonce . $cipher);
    32|    }
    33|
    34|    /**
    35|     * Dekrypterer tekst med samme 256-bit nøkkel.
    36|     *
    37|     * @param string $encryptedData Base64-kodet data (nonce + ciphertext)
    38|     * @param string $key Base64-kodet 256-bit nøkkel fra nøkkelfil
    39|     * @return string|null Klartekst eller null hvis dekryptering feiler
    40|     */
    41|    public static function decrypt(string $encryptedData, string $key): ?string
    42|    {
    43|        $decoded = base64_decode($encryptedData, true);
    44|
    45|        if ($decoded === false || strlen($decoded) < self::NONCE_LENGTH + 1) {
    46|            return null;
    47|        }
    48|
    49|        $binaryKey = base64_decode($key, true);
    50|        
    51|        if ($binaryKey === false || strlen($binaryKey) !== self::KEY_LENGTH) {
    52|            return null;
    53|        }
    54|
    55|        $nonce = substr($decoded, 0, self::NONCE_LENGTH);
    56|        $cipher = substr($decoded, self::NONCE_LENGTH);
    57|
    58|        $plaintext = sodium_crypto_secretbox_open($cipher, $nonce, $binaryKey);
    59|
    60|        sodium_memzero($binaryKey);
    61|
    62|        return $plaintext === false ? null : $plaintext;
    63|    }
